import React, { Component } from 'react';
import { Link } from 'react-router-dom';

class Project extends Component {
  render() {
    const { name, des, img } = this.props.project;
    return (
      <div className="picture">
        <div className="content">
          <div className="text">
            <h2>{name}</h2>
            <ul>
              <li>{desc}</li>
            </ul>
          </div>
        </div>
        <img src={img} alt="" />
      </div>
    );
  }
}

export default Project;
